```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <type_traits>
#include <utility>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Map table name to corresponding struct type
  static const std::map<std::string, std::pair<std::string, size_t>> table_map = {
    {"Student", {transpilation::get_table_or_view<T>(), sizeof(Student)}},
    {"Course", {transpilation::get_table_or_view<T>(), sizeof(Course)}},
    {"Score", {transpilation::get_table_or_view<T>(), sizeof(Score)}},
    {"Major", {transpilation::get_table_or_view<T>(), sizeof(Major)}}
  };

  // Get the correct type based on table name
  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  // Ensure we're using the correct type for the table
  if (it->second.first != transpilation::get_table_or_view<T>()) {
    throw std::invalid_argument("Type mismatch for table: " + table_name);
  }

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Use sqlgen::write to insert records
  auto write_result = sqlgen::write(conn, records);
  if (!write_result) {
    throw std::runtime_error("Failed to write records to database");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table name to corresponding struct type and primary key type
  static const std::map<std::string, std::tuple<std::string, std::string, std::string>> table_map = {
    {"Student", {"Student", "SNo", "sqlgen::Varchar<10>"}},
    {"Course", {"Course", "CID", "uint32_t"}},
    {"Score", {"Score", "ScID", "uint32_t"}},
    {"Major", {"Major", "MID", "uint32_t"}}
  };

  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  std::string type_name = it->second.template get<0>();
  std::string pk_name = it->second.template get<1>();
  std::string pk_type = it->second.template get<2>();

  // Convert record_id to appropriate type
  std::optional<std::string> converted_id;
  if (pk_type == "uint32_t") {
    try {
      uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
      converted_id = std::to_string(id);
    } catch (const std::exception& e) {
      throw std::invalid_argument("Invalid record ID for " + table_name + ": " + record_id);
    }
  } else {
    converted_id = record_id;
  }

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Use sqlgen::delete_from with where condition
  auto delete_stmt = sqlgen::delete_from<sqlgen::dynamic::Table{type_name}> 
                    | sqlgen::where("id"_c == converted_id);

  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    throw std::runtime_error("Failed to delete record from " + table_name);
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
  // Map table name to corresponding struct type and column types
  static const std::map<std::string, std::tuple<std::string, std::map<std::string, std::string>> table_map = {
    {"Student", {
        "Student",
        {
          {"SNo", "sqlgen::Varchar<10>"},
          {"SName", "sqlgen::Varchar<30>"},
          {"Sex", "int"},
          {"Birthday", "std::optional<sqlgen::DateTime>"},
          {"Major", "std::optional<uint32_t>"},
          {"Scorses", "std::optional<double>"},
          {"Remark", "std::optional<std::string>"}
        }
      }},
    {"Course", {
        "Course",
        {
          {"CID", "uint32_t"},
          {"CName", "sqlgen::Varchar<50>"},
          {"Term", "std::optional<int>"},
          {"CTime", "std::optional<int>"},
          {"Credit", "int"}
        }
      }},
    {"Score", {
        "Score",
        {
          {"ScID", "uint32_t"},
          {"SNo", "sqlgen::ForeignKey<sqlgen::Varchar<10>, Student, \"SNo\">"},
          {"CID", "sqlgen::ForeignKey<uint32_t, Course, \"CID\">"},
          {"Score", "std::optional<double>"}
        }
      }},
    {"Major", {
        "Major",
        {
          {"MID", "uint32_t"},
          {"MName", "sqlgen::Varchar<30>"}
        }
      }}
  };

  auto it = table_map.find(table_name);
  if (it == table_map.end()) {
    throw std::invalid_argument("Invalid table name: " + table_name);
  }

  std::string type_name = it->second.template get<0>();
  auto columns = it->second.template get<1>();

  // Validate column name
  if (columns.find(col_name) == columns.end()) {
    throw std::invalid_argument("Invalid column name: " + col_name + " for table " + table_name);
  }

  // Convert new_value to appropriate type
  std::optional<std::string> typed_value;
  std::string type_str = columns[col_name];

  if (type_str == "int" || type_str == "uint32_t") {
    try {
      int value = std::stoi(new_value);
      typed_value = std::to_string(value);
    } catch (const std::exception& e) {
      throw std::invalid_argument("Invalid integer value for column: " + col_name);
    }
  } else if (type_str == "double") {
    try {
      double value = std::stod(new_value);
      typed_value = std::to_string(value);
    } catch (const std::exception& e) {
      throw std::invalid_argument("Invalid double value for column: " + col_name);
    }
  } else if (type_str == "sqlgen::Varchar<10>" || type_str == "sqlgen::Varchar<30>" || type_str == "sqlgen::Varchar<50>") {
    typed_value = new_value;
  } else if (type_str == "std::optional<int>" || type_str == "std::optional<uint32_t>" || 
             type_str == "std::optional<double>" || type_str == "std::optional<std::string>") {
    if (new_value.empty()) {
      typed_value = std::nullopt;
    } else {
      // Determine the underlying type from the optional
      std::string underlying_type = type_str.substr(10); // Remove "std::optional<"
      underlying_type.pop_back(); // Remove closing bracket

      if (underlying_type == "int" || underlying_type == "uint32_t") {
        try {
          int value = std::stoi(new_value);
          typed_value = std::to_string(value);
        } catch (const std::exception& e) {
          throw std::invalid_argument("Invalid integer value for optional column: " + col_name);
        }
      } else if (underlying_type == "double") {
        try {
          double value = std::stod(new_value);
          typed_value = std::to_string(value);
        } catch (const std::exception& e) {
          throw std::invalid_argument("Invalid double value for optional column: " + col_name);
        }
      } else if (underlying_type == "std::string") {
        typed_value = new_value;
      }
    }
  } else {
    throw std::invalid_argument("Unsupported column type: " + type_str);
  }

  // Connect to database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Use sqlgen::update with set and where conditions
  auto update_stmt = sqlgen::update<sqlgen::dynamic::Table{type_name}>(
    "column"_c.set(typed_value)  // Note: This would need proper column name handling
  ) | sqlgen::where("id"_c == record_id);

  auto update_result = update_stmt(conn);
  if (!update_result) {
    throw std::runtime_error("Failed to update record in " + table_name);
  }
}
