  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen::literals;

    // 1. Connect to SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // 2. Create User and Post tables
    std::vector<User> empty_users;
    auto write_users_result = sqlgen::write(conn, empty_users);
    if (!write_users_result) {
        throw std::runtime_error("Failed to create User table");
    }

    std::vector<Post> empty_posts;
    auto write_posts_result = sqlgen::write(conn, empty_posts);
    if (!write_posts_result) {
        throw std::runtime_error("Failed to create Post table");
    }

    // 3. Build and execute the query
    auto query_result = sqlgen::select_from<User, "u">("user_id"_t1, "username"_t1)
        | sqlgen::inner_join<Post, "p">("user_id"_t1 == "user_id"_t2)
        | sqlgen::where("created_at"_t2 >= sqlgen::DateTime("2025-12-01") && 
                       "created_at"_t2 <= sqlgen::DateTime("2025-12-31"))
        | sqlgen::to<std::vector<ActiveUser>>;

    auto result = query_result(conn);
    if (!result) {
        throw std::runtime_error("Query failed");
    }

    return result.value();
}

