      {3, "home", "2023-10-01 12:00:00"}, // Duplicate URL same day

      {4, "products", "2023-10-02 09:00:00"},
      {5, "products", "2023-10-02 09:30:00"}, // Duplicate URL same day

      {6, "contact", "2023-10-03 15:00:00"}
