  auto conn_result = sqlgen::sqlite::connect(":memory:");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create tables using sqlgen::write
  auto user_table = sqlgen::write(users);
  auto friendship_table = sqlgen::write(friendships);

  // Execute table creation
  conn->execute(sqlgen::sqlite::to_sql(user_table));
  conn->execute(sqlgen::sqlite::to_sql(friendship_table));

  // Insert data
  conn->write(users.begin(), users.end());
  conn->write(friendships.begin(), friendships.end());

  // Query 1: Mutual friends using self-join
  auto mutual_friends_query = sqlgen::read<std::vector<MutualFriends>>
    | sqlgen::inner_join<"f1"_t1, Friendship>("u1"_t1, "user_id"_t1 == "user1_id"_t2)
