  for (const auto& fof : friend_of_friend_results.value()) {
    results.push_back(FriendConnection{fof.user1_name, fof.user2_name});
  }

  // Add same city non-friends recommendations
  for (const auto& sc : same_city_results.value()) {
    results.push_back(FriendConnection{sc.user1_name, sc.user2_name});
  }

  return results;
}

}  // namespace analyze_social_network
