  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen::literals;

  // 1. Create SQLite database connection
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Use sqlgen's write functionality to insert OrderItem data into a table
  auto write_result = sqlgen::write(conn, items);
  if (!write_result) {
    throw std::runtime_error("Failed to write OrderItem data");
  }

  // 3. Use sqlgen's read functionality with arithmetic operations to calculate metrics
  auto query = sqlgen::select_from<OrderItem>(
    "item_id"_c,
    "order_id"_c, 
    "product_id"_c,
    "unit_price"_c,
    "quantity"_c,
    "discount_rate"_c,
    "tax_rate"_c,

    // Arithmetic operations for business metrics
    ("unit_price"_c * "quantity"_c).as<"gross_total">(),
    (("unit_price"_c * "quantity"_c) * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100)).as<"discounted_total">(),
    ((("unit_price"_c * "quantity"_c) * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100)) * (1 + sqlgen::coalesce("tax_rate"_c, 0.0)/100)).as<"final_total">(),
    (("unit_price"_c * "quantity"_c) / "quantity"_c).as<"unit_cost">(),
    ("quantity"_c % 10).as<"quantity_group">(),
    ("unit_price"_c * 0.3).as<"estimated_profit">()
  ) | sqlgen::to<std::vector<OrderMetrics>>;

  // 4. Execute the query and return results
  auto result = query(conn);
  if (!result) {
    throw std::runtime_error("Failed to execute query");
  }

  return result.value();
}

}  // namespace calculate_order_metrics

